SELECT [AnalisiCredito-step0-datiVendite].[Sell-to Customer No_] AS CodiceCliente, [AnalisiCredito-step1-datiSaldoClienti].No_, [AnalisiCredito-step0-datiVendite].[Purchase Group], [AnalisiCredito-step0-datiVendite].Name, [AnalisiCredito-step0-datiVendite].[Name 2], [AnalisiCredito-step0-datiVendite].Address, [AnalisiCredito-step0-datiVendite].[Post Code], [AnalisiCredito-step0-datiVendite].City, [AnalisiCredito-step0-datiVendite].County, [AnalisiCredito-step0-datiVendite].[Country_region Code], [AnalisiCredito-step0-datiVendite].[VAT Registration No_], [AnalisiCredito-step0-datiVendite].[Fiscal Code], [AnalisiCredito-step0-datiVendite].[Payment Method Code], [AnalisiCredito-step0-datiVendite].[Risk Rating], [AnalisiCredito-step0-datiVendite].[PM Failure Assigned Score], [AnalisiCredito-step0-datiVendite].[Current Risk], [AnalisiCredito-step0-datiVendite].DataAggiornamento, [AnalisiCredito-step0-datiVendite].DataValutazione, [AnalisiCredito-step0-datiVendite].DataScadenza, [AnalisiCredito-step0-datiVendite].[Updated Type], [AnalisiCredito-step0-datiVendite].[Skip Credit Info Update], 0 AS SaldoD, [AnalisiCredito-step0-datiVendite].[Currency Code], [AnalisiCredito-step0-datiVendite].ValueSoldStagione1, [AnalisiCredito-step0-datiVendite].ValueOutstandingStagione1, [AnalisiCredito-step0-datiVendite].ValueSoldStagione2, [AnalisiCredito-step0-datiVendite].ValueOutstandingStagione2, [AnalisiCredito-step0-datiVendite].ValueReturnStagione1, [AnalisiCredito-step0-datiVendite].ValueReturnStagione2
FROM [AnalisiCredito-step1-datiSaldoClienti] RIGHT JOIN [AnalisiCredito-step0-datiVendite] ON [AnalisiCredito-step1-datiSaldoClienti].No_ = [AnalisiCredito-step0-datiVendite].[Sell-to Customer No_]
WHERE ((([AnalisiCredito-step1-datiSaldoClienti].No_) Is Null));

